// Route: Initiate OIDC login
app.get('/auth/login', (req, res) => {
  // Generate state parameter for CSRF protection
  const state = crypto.randomBytes(32).toString('hex');
  // Generate nonce for replay protection
  const nonce = crypto.randomBytes(32).toString('hex');

  // Store state and nonce in session for verification
  req.session.oidcState = state;
  req.session.oidcNonce = nonce;

  const authorizationUrl = new URL(OIDC_CONFIG.authorizationEndpoint);
  authorizationUrl.searchParams.set('response_type', 'code');
  authorizationUrl.searchParams.set('client_id', OIDC_CONFIG.clientId);
  authorizationUrl.searchParams.set('redirect_uri', OIDC_CONFIG.redirectUri);
  authorizationUrl.searchParams.set('scope', OIDC_CONFIG.scope);
  authorizationUrl.searchParams.set('state', state);
  authorizationUrl.searchParams.set('nonce', nonce);

  console.log(`Redirecting to OIDC provider for authentication...`);
  res.redirect(authorizationUrl.toString());
});

// Route: OIDC Callback - Handle authorization code
app.get('/auth/callback', async (req, res) => {
  const { code, state, error, error_description } = req.query;

  // Handle error response from OIDC provider
  if (error) {
    console.error(`OIDC Error: ${error} - ${error_description}`);
    return res.status(400).json({
      error: 'Authentication failed',
      details: error_description || error,
    });
  }

  // Verify authorization code is present
  if (!code) {
    return res.status(400).json({ error: 'Authorization code not received' });
  }

  // Verify state parameter to prevent CSRF
  if (!state || state !== req.session.oidcState) {
    return res.status(403).json({ error: 'Invalid state parameter. Possible CSRF attack.' });
  }

  try {
    // Exchange authorization code for tokens
    console.log('Exchanging authorization code for tokens...');
    const tokenResponse = await axios.post(
      OIDC_CONFIG.tokenEndpoint,
      new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OIDC_CONFIG.redirectUri,
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret,
      }).toString(),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
      }
    );

    const { access_token, id_token, refresh_token, token_type, expires_in } = tokenResponse.data;

    if (!id_token) {
      return res.status(400).json({ error: 'No id_token received from token endpoint' });
    }

    console.log('Tokens received successfully. Decoding id_token...');

    // WARNING: jwt.decode() does NOT verify the signature.
    // In production, you MUST use jwt.verify() with the provider's public key (from JWKS)
    // to ensure the token hasn't been tampered with.
    // Using jwt.decode() here for demonstration - see the note below for proper verification.
    const decodedIdToken = jwt.decode(id_token, { complete: true });

    if (!decodedIdToken) {
      return res.status(400).json({ error: 'Failed to decode id_token' });
    }

    console.log('id_token decoded successfully');
    console.log('Token header:', JSON.stringify(decodedIdToken.header));

    // Validate essential claims
    const validatedClaims = validateIdTokenClaims(decodedIdToken);

    // Verify nonce to prevent replay attacks
    if (validatedClaims.nonce !== req.session.oidcNonce) {
      return res.status(403).json({ error: 'Invalid nonce. Possible replay attack.' });
    }

    // Extract user information from id_token claims
    const userInfo = {
      sub: validatedClaims.sub,                          // Subject identifier (unique user ID)
      email: validatedClaims.email || null,               // User's email
      emailVerified: validatedClaims.email_verified || false,
      name: validatedClaims.name || null,                 // User's full name
      givenName: validatedClaims.given_name || null,      // First name
      familyName: validatedClaims.family_name || null,    // Last name
      preferredUsername: validatedClaims.preferred_username || null,
      picture: validatedClaims.picture || null,           // Profile picture URL
      locale: validatedClaims.locale || null,
    };

    console.log('User info extracted from id_token:', JSON.stringify(userInfo, null, 2));

    // Create user session with decoded claims
    req.session.user = userInfo;
    req.session.tokens = {
      accessToken: access_token,
      idToken: id_token,
      refreshToken: refresh_token || null,
      tokenType: token_type,
      expiresAt: expires_in ? Date.now() + (expires_in * 1000) : null,
    };
    req.session.authenticatedAt = new Date().toISOString();

    // Clean up OIDC state from session
    delete req.session.oidcState;
    delete req.session.oidcNonce;

    // Regenerate session to prevent session fixation
    req.session.regenerate((err) => {
      if (err) {
        console.error('Session regeneration error:', err);
      }

      // Re-set user data after regeneration
      req.session.user = userInfo;
      req.session.tokens = {
        accessToken: access_token,
        idToken: id_token,
        refreshToken: refresh_token || null,
        tokenType: token_type,
        expiresAt: expires_in ? Date.now() + (expires_in * 1000) : null,
      };
      req.session.authenticatedAt = new Date().toISOString();

      req.session.save((saveErr) => {
        if (saveErr) {
          console.error('Session save error:', saveErr);
          return res.status(500).json({ error: 'Failed to create session' });
        }

        console.log(`User session created for: ${userInfo.email || userInfo.sub}`);
        res.redirect('/auth/profile');
      });
    });

  } catch (error) {
    console.error('Token exchange error:', error.response?.data || error.message);
    return res.status(500).json({
      error: 'Failed to exchange authorization code for tokens',
      details: error.response?.data?.error_description || error.message,
    });
  }
});

